$historyPaths = @("$env:APPDATA\Code\User\History", "$env:APPDATA\Cursor\User\History"); $results = @(); foreach ($historyPath in $historyPaths) { if (Test-Path $historyPath) { Get-ChildItem -Path $historyPath -Recurse -Filter "entries.json" -ErrorAction SilentlyContinue | ForEach-Object { $content = Get-Content $_.FullName | ConvertFrom-Json; $resource = $content.resource; if ($resource -match "BentoGridSection.tsx|BentoGridIntro.tsx|BentoGrid.tsx|AboutOregent.tsx") { foreach ($entry in $content.entries) { $results += [PSCustomObject]@{ Resource = $resource; Path = "$($_.DirectoryName)\$($entry.id)"; Timestamp = $entry.timestamp; Date = (Get-Date -Date "1970-01-01 00:00:00Z").AddMilliseconds($entry.timestamp).ToLocalTime() } } } } } }; $results | Sort-Object Timestamp -Descending | Export-Csv -Path "d:\OREHACK\cursor_hist.csv" -NoTypeInformation
